/// Returns the basename using both Windows and Unix path separators.
pub fn reference_file_name(file_name_or_path: &str) -> &str {
    file_name_or_path
        .rsplit(['\\', '/'])
        .next()
        .unwrap_or(file_name_or_path)
}

