+1957     fn download_apply_and_cleanup<D, A>(
+1958         &self,
+1959         request_id: u64,
+1960         game_root: &Path,
+1961         row: &DowngraderPreviewPlanRow,
+1962         current_backup_path: &Path,
+1963         downloader: &D,
+1964         applier: &A,
+1965         progress_events: &mut Vec<DowngraderExecutionProgressEvent>,
+1966         mut diagnostics: Vec<String>,
+1967     ) -> RowExecutionStatus
+1968     where
+1969         D: DeltaDownloader + ?Sized,
+1970         A: DeltaApplier + ?Sized,
+1971     {
+1972         let source_bytes = match self.filesystem.read_bytes(current_backup_path) {
+1973             Ok(bytes) => bytes,
+1974             Err(error) => {
+1975                 return RowExecutionStatus::Failed {
+1976                     diagnostics: vec![mutation_diagnostic(
+1977                         row,
+1978                         DowngraderPlanStepKind::ApplyDeltaPatch,
+1979                         error.user_message(),
+1980                     )],
+1981                 };
+1982             }
+1983         };
+1984         let patch_path = game_root.join(&row.plan.patch_name);
+1985         let patch_bytes = match self.read_or_download_patch(request_id, row, &patch_path, downloader, progress_events) {
+1986             Ok(bytes) => bytes,
+1987             Err(diagnostic) => return RowExecutionStatus::Failed { diagnostics: vec![diagnostic] },
+1988         };
+1989         let output_bytes = match applier.apply_delta(&source_bytes, &patch_bytes) {
+1990             Ok(bytes) => bytes,
+1991             Err(error) => {
+1992                 warn!(
+1993                     event = "downgrader-execute-apply-failed",
+1994                     request_id,
+1995                     relative_path = row.plan.relative_path,
+1996                     diagnostic = error.diagnostic(),
+1997                     "Downgrader delta apply failed"
+1998                 );
+1999                 return RowExecutionStatus::Failed {
+2000                     diagnostics: vec![format!(
+2001                         "{} {}",
+2002                         error.user_message(),
+2003                         error.diagnostic()
+2004                     )],
+2005                 };
+2006             }
+2007         };
+2008         let output_crc = crc32_hex(&output_bytes);
+2009         if !crc_is_desired_target_for_plan(&output_crc, row.plan.target) {
+2010             return RowExecutionStatus::Failed {
+2011                 diagnostics: vec![format!(
+2012                     "{} patch output CRC {output_crc} did not match target {}.",
+2013                     row.plan.display_name,
+2014                     row.plan.target.as_reference_str()
+2015                 )],
+2016             };
+2017         }
+2018 
+2019         if let Err(error) = self.filesystem.write_bytes(&row.current_path, &output_bytes) {
+2020             return RowExecutionStatus::Failed {
+2021                 diagnostics: vec![mutation_diagnostic(
+2022                     row,
+2023                     DowngraderPlanStepKind::ApplyDeltaPatch,
+2024                     error.user_message(),
+2025                 )],
+2026             };
+2027         }
+2028         if !row.options().keep_backups {
+2029             if let Err(diagnostic) = self.remove_file_with_context(
+2030                 current_backup_path,
+2031                 row,
+2032                 DowngraderPlanStepKind::DeleteCurrentBackup,
+2033             ) {
+2034                 return RowExecutionStatus::Failed { diagnostics: vec![diagnostic] };
+2035             }
+2036         }
+2037         if row.options().delete_deltas {
+2038             if let Err(diagnostic) = self.remove_file_with_context(
+2039                 &patch_path,
+2040                 row,
+2041                 DowngraderPlanStepKind::DeleteDeltaPatch,
+2042             ) {
+2043                 return RowExecutionStatus::Failed { diagnostics: vec![diagnostic] };
+2044             }
+2045         }
+2046 
+2047         diagnostics.push(format!(
+2048             "{} patched with {}.",
+2049             row.plan.display_name, row.plan.patch_name
+2050         ));
+2051         RowExecutionStatus::Patched { diagnostics }
+2052     }
