+2054     fn read_or_download_patch<D>(
+2055         &self,
+2056         request_id: u64,
+2057         row: &DowngraderPreviewPlanRow,
+2058         patch_path: &Path,
+2059         downloader: &D,
+2060         progress_events: &mut Vec<DowngraderExecutionProgressEvent>,
+2061     ) -> Result<Vec<u8>, String>
+2062     where
+2063         D: DeltaDownloader + ?Sized,
+2064     {
+2065         match self.filesystem.metadata(patch_path) {
+2066             Ok(metadata) if metadata.is_file() => self
+2067                 .filesystem
+2068                 .read_bytes(patch_path)
+2069                 .map_err(|error| mutation_diagnostic(row, DowngraderPlanStepKind::DownloadDelta, error.user_message())),
+2070             Ok(_) => Err(mutation_diagnostic(
+2071                 row,
+2072                 DowngraderPlanStepKind::DownloadDelta,
+2073                 "Delta patch path is not a file.",
+2074             )),
+2075             Err(error) if error.kind == PlatformErrorKind::NotFound => {
+2076                 let mut progress = |progress: DowngraderProgress| {
+2077                     progress_events.push(DowngraderExecutionProgressEvent {
+2078                         request_id,
+2079                         relative_path: row.plan.relative_path,
+2080                         patch_name: row.plan.patch_name.clone(),
+2081                         progress,
