+2085                     .download_delta(&row.plan.patch_url, &mut progress)
+2086                     .map_err(|error| {
+2087                         warn!(
+2088                             event = "downgrader-execute-download-failed",
+2089                             request_id,
+2090                             relative_path = row.plan.relative_path,
+2091                             patch_name = row.plan.patch_name,
+2092                             diagnostic = error.diagnostic(),
+2093                             "Downgrader delta download failed"
+2094                         );
+2095                         format!("{} {}", error.user_message(), error.diagnostic().unwrap_or(""))
+2096                     })?;
+2097                 self.filesystem
+2098                     .write_bytes(patch_path, &bytes)
+2099                     .map_err(|error| mutation_diagnostic(row, DowngraderPlanStepKind::DownloadDelta, error.user_message()))?;
+2100                 Ok(bytes)
+2101             }
+2102             Err(error) => Err(mutation_diagnostic(
+2103                 row,
+2104                 DowngraderPlanStepKind::DownloadDelta,
+2105                 error.user_message(),
+2106             )),
+2107         }
+2108     }
