            self.check_mutation_allowed(PlatformOperation::RenameFile, from)?;
            let node = self.node(from, PlatformOperation::RenameFile)?;
            self.ensure_parent_dirs(to);
            let mut nodes = self.nodes.borrow_mut();
            nodes.remove(from);
            nodes.insert(to.to_path_buf(), node);
            self.mutations.borrow_mut().push(FsMutation::Rename {
                from: from.to_path_buf(),
                to: to.to_path_buf(),
            });
            Ok(())
        }

        fn remove_file(&self, path: &Path) -> PlatformResult<()> {
            self.check_mutation_allowed(PlatformOperation::RemoveFile, path)?;
            match self.nodes.borrow().get(path) {
                Some(FakeNode::File(_) | FakeNode::UnreadableFile) => {}
                Some(FakeNode::Directory) => {
                    return Err(PlatformError::new(
