    ) -> RowExecutionStatus
    where
        D: DeltaDownloader + ?Sized,
        A: DeltaApplier + ?Sized,
    {
        let row = context.row;
        let source_bytes = match self.filesystem.read_bytes(context.current_backup_path) {
